import React from "react";
import "./CalendarGrid.css";

const DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

const CalendarGrid = ({
  currentDate = new Date(),
  events = [],
  activeFilters = { holiday: true, leave: true, birthday: true },
  viewMode = "month",
}) => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const today = new Date();

  const startOfMonth = new Date(year, month, 1);
  const endOfMonth = new Date(year, month + 1, 0);

  const startOfWeek = new Date(currentDate);
  startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

  const days = [];

  if (viewMode === "month") {
    for (let i = 0; i < startOfMonth.getDay(); i++) {
      days.push(null);
    }

    for (let d = 1; d <= endOfMonth.getDate(); d++) {
      days.push(new Date(year, month, d));
    }
  } else {
    for (let i = 0; i < 7; i++) {
      const day = new Date(startOfWeek);
      day.setDate(startOfWeek.getDate() + i);
      days.push(day);
    }
  }

  return (
    <>
      {/* DAYS HEADER */}
      <div className="days-row">
        {DAYS.map((day) => (
          <div key={day} className="day-name">
            {day}
          </div>
        ))}
      </div>

      {/* DATE GRID */}
      <div className="calendar-grid">
        {days.map((day, index) => {
          const isToday =
            day &&
            day.getDate() === today.getDate() &&
            day.getMonth() === today.getMonth() &&
            day.getFullYear() === today.getFullYear();

          return (
            <div
              key={index}
              className={`calendar-cell light-cell ${
                isToday ? "today" : ""
              }`}
            >
              {day && (
                <>
                  <span className="date-number">{day.getDate()}</span>

                  {events
                    .filter((e) => {
                      const eventDate = new Date(e.date);
                      return (
                        eventDate.toDateString() === day.toDateString() &&
                        activeFilters[e.type]
                      );
                    })
                    .map((e, i) => (
                      <div key={i} className={`event ${e.type}`}>
                        {e.title}
                      </div>
                    ))}
                </>
              )}
            </div>
          );
        })}
      </div>
    </>
  );
};

export default CalendarGrid;
